sei-sthane amara parama gopyapuri',NULL,NULL),('cb.antya.2.367','cb','cb.antya.2','ЧБ Антья 2.367',367,NULL,'sei sthana siva, aji kahi toma''-sthane se purira marma mora keha nahi jane',NULL,NULL),('cb.antya.2.368','cb','cb.antya.2','ЧБ Антья 2.368',368,NULL,'sindhu-tire vata-mule ''nilacala'' nama ksetra-sri-purusottama-ati ramya-sthana
lavanambho-nidhes tire purusottama-samjnakam puram tad brahmana-srestha svargad api su-durlabham
svayam asti pure tasmin yatah sri-purusottamah purusottamam ity uktam tasmat tan nama-kovidaih
ksetram tad durlabham vipra samantad dasa-yojanam tatra-stha dehino devair drsyante ca catur-bhujah
pravisantas tu tat ksetram sarve syur visnu-murtayah tasmad vicarana tatra na kartavya vicaksanaih
candalenapi samsprstam grahyam tatrannam agrajaih saksad visnur yatas tatra candalo ''pi dvijottamah
tatranna-pacika laksmih svayam bhokta janardanah
tasmat tad annam viprarse daivatair api durlabham
hari-bhuktavasistam tat pavitram bhuvi durlabham annam ye bhunjate martyas tesam muktir na durlabha
brahmadyas tridasah sarve tad annam ati-durlabham
bhunjate nityam adrtya manusyanam ca ka katha
na yasya ramate cittam tasminn anne su-durlabhe tam eva visnu-dvestaram prahuh sarve maharsayah
pavitram bhuvi sarvatra yatha ganga-jalam dvija tatha pavitram sarvatra tad annam papa-nasanam
tad annam komalam divyam yadyapi dvija-sattama
tathapi vajra-tulyam syat papa-parvata-darane
purvarjitani papani ksayam yasyanti yasya vai bhaktih pravartate tasminn anne tasya su-durlabhe
bahu-janmarjitam punyam yasya yasyati sanksayam
tasminn anne dvija-srestha tasya bhaktih pravartate',NULL,NULL),('cb.antya.2.369','cb','cb.antya.2','ЧБ Антья 2.369',369,NULL,'ananta brahmanda kale yakhana samhare
tabu se sthanera kichu karite na pare',NULL,NULL),('cb.antya.2.370','cb','cb.antya.2','ЧБ Антья 2.370',370,NULL,'sarva-kala sei sthane amara vasati prati-dina amara bhojana haya tathi
se sthanera prabhave yojana dasa bhumi tahate vasaye yata jantu, kita, krmi
sabare dekhaye catur-bhuja deva-gane
''bhuvana-mangala'' kari'' kahiye ye sthane',NULL,NULL),('cb.antya.2.373','cb','cb.antya.2','ЧБ Антья 2.373',373,NULL,'nidrate о ye sthane samadhi-phala haya sayane pranama-phala yatha vede kaya',NULL,NULL),('cb.antya.2.374','cb','cb.antya.2','ЧБ Антья 2.374',374,NULL,'pradaksina-phala paya karile bhramana katha matra yatha haya amara stavana',NULL,NULL),('cb.antya.2.375','cb','cb.antya.2','ЧБ Антья 2.375',375,NULL,'hena se ksetrera ati prabhava nirmala matsya khaile о paya havisyera phala',NULL,NULL),('cb.antya.2.376','cb','cb.antya.2','ЧБ Антья 2.376',376,NULL,'nija-name sthana mora hena priyatama
tahate yateka vaise, se amara sama',NULL,NULL),('cb.antya.2.377','cb','cb.antya.2','ЧБ Антья 2.377',377,NULL,'se sthane nahika yama-danda-adhikara
ami kari bhala-manda-vicara sabara',NULL,NULL),('cb.antya.2.378','cb','cb.antya.2','ЧБ Антья 2.378',378,NULL,'hena se amara puri, tahara uttare tomare dilana sthana rahibara tare',NULL,NULL),('cb.antya.2.379','cb','cb.antya.2','ЧБ Антья 2.379',379,NULL,'bhukti-mukti-prada sei sthana manohara tatha tumi khyata haiba ''sri-bhuvanesvara''"',NULL,NULL),('cb.antya.2.380','cb','cb.antya.2','ЧБ Антья 2.380',380,NULL,'suniya adbhuta puri-mahima sankara
punah sri-carana dhari'' karila uttara',NULL,NULL),('cb.antya.2.381','cb','cb.antya.2','ЧБ Антья 2.381',381,NULL,'"suna prana-natha, mora eka nivedana
muni se parama ahankrta sarva-ksana',NULL,NULL),('cb.antya.2.382','cb','cb.antya.2','ЧБ Антья 2.382',382,NULL,'eteke tomare chadi'' ami anya sthane thakile kusala mora nahika kakhane',NULL,NULL),('cb.antya.2.383','cb','cb.antya.2','ЧБ Антья 2.383',383,NULL,'tomara nikate thaki sabe mora mana dusta-sanga-dose bhala nahika kakhana',NULL,NULL),('cb.antya.2.384','cb','cb.antya.2','ЧБ Антья 2.384',384,NULL,'eteke amare yadi thake bhrtya-jnana tabe nija-ksetre more deha'' eka sthana',NULL,NULL),('cb.antya.2.385','cb','cb.antya.2','ЧБ Антья 2.385',385,NULL,'ksetrera mahima suni'' sri-mukhe tomara
bada iccha haila tatha thakite amara',NULL,NULL),('cb.antya.2.386','cb','cb.antya.2','ЧБ Антья 2.386',386,NULL,'nikrsta haiya prabhu, sevimu tomare tathaya tileka sthana deha'' prabhu, more',NULL,NULL);
INSERT OR REPLACE INTO verse_texts (id,verse_id,edition_id,translation,purport) VALUES ('cb.antya.2.257.ru','cb.antya.2.257','cb-ru','Гаурачандра учил всех, "Все вы должны быть почтительными с Нитьянандой".',NULL),('cb.antya.2.258.ru','cb.antya.2.258','cb-ru','"Тело Нитьянанды для Меня важнее собственного. Я уверяю вас, что это истина".',NULL),('cb.antya.2.259.ru','cb.antya.2.259','cb-ru','"Я не несу ответственности за трудности, которые возникнут на пути обретения экстатической любви у того, кто оскорбляет стопы Нитьянанды".',NULL),('cb.antya.2.260.ru','cb.antya.2.260','cb-ru','"Если человек испытывает хоть малейшую зависть к Нитьянанде, он не дорог Мне, даже если он Мой преданный".',NULL),('cb.antya.2.261.ru','cb.antya.2.261','cb-ru','Когда Нитьянанда услышал как Его прославляет Господь, Он смутился и опустил голову.',NULL),('cb.antya.2.262.ru','cb.antya.2.262','cb-ru','Тем не менее, все преданные были счастливы. Таковы игры Шри Шачинанданы.',NULL),('cb.antya.2.263.ru','cb.antya.2.263','cb-ru','Переночевав в Джалешваре, Господь с преданными рано утром двинулся дальше.',NULL),('cb.antya.2.264.ru','cb.antya.2.264','cb-ru','На пути к Вамшадахе Господь встретил одного санньяси-шакту, который пытался дать Господу наставления.
Другие названия для Вамшадахи это Вамшада и Вамшадха. Этот населённый пункт находится недалеко от Джалешвары.',NULL),('cb.antya.2.265.ru','cb.antya.2.265','cb-ru','Господь знал, что тот был шактой, то есть поклонником богини Дурги, но очень мило заговорил с ним.',NULL),('cb.antya.2.266.ru','cb.antya.2.266','cb-ru','Господь сказал, "Расскажи Мне, где же ты был? Прошло так много времени, прежде чем Я нашел Своего друга".',NULL),('cb.antya.2.267.ru','cb.antya.2.267','cb-ru','Сбитый с толку иллюзорной энергией Господа, шакта начал рассказывать о себе.',NULL),('cb.antya.2.268.ru','cb.antya.2.268','cb-ru','Шакта рассказал Господу о всех поклонниках Дурги в разных провинциях, которых он знал, а Господь улыбаясь слушал его.',NULL),('cb.antya.2.269.ru','cb.antya.2.269','cb-ru','Шакта сказал, "Приглашаю всех к себе в монастырь. ‘Благостного’ напитка хватит на всех".',NULL),('cb.antya.2.270.ru','cb.antya.2.270','cb-ru','Понимая, что греховный шакта намекал на вино, Гаурачандра и Нитьянанда не сдержали улыбок.
Фраза папи шакта – это поклонники Шакти (Дурги), которые наслаждаются материальным счастьем в состоянии алкогольного опьянения, напившись вина, очень падкие на греховные поступки. В конечном счёте их духовное продвижение – полное надувательство. Панча-Макара – мамса (мясо), мадья (вино), матсйа (рыба), махила (женщины), а майтхуна (секс) – это источник наслаждения для их материальных тел.',NULL),('cb.antya.2.271.ru','cb.antya.2.271','cb-ru','Господь сказал, "Я приду, чтобы насладиться блаженством, а ты иди вперёд и подготовься".
Поскольку многие глупые люди не в состоянии понять истину, они считают чувственные удовольствия, порождённые невежеством, целью своей жизни. Из-за того, что люди привлечённые философией шакты, поют славу собственным чувственным наслаждениям, им не понять суть беспримесного служения Адхокшадже. Пракрита-сахаджии заслуживают того, чтобы их называли "папи-шакта". Их цель жизни – материальные наслаждения. Шри Гаурасундара при встрече с такими пракрита-сахаджиями просто обводил их вокруг пальца, делая вид, что одобряет их деятельность. Самые чистые духовные учители этих падших душ и сейчас привлекают многих людей, заинтересованных в материальных наслаждениях, следуя примеру, показанному Шри Чайтаньей. Люди привлечённые материальными наслаждениями думают, что вайшнавы, как и они, жаждут и действуют ради известности и славы. Такие пракрита-сахаджии, или греховные шакты, не знают, что расставляя свои нечестивые сети, с целью привязать вайшнавов к образу жизни домохозяев и искушая их домашними удобствами, они получат гневный отпор вайшнавов, самых чистых из преданных. Вайшнав никогда не переступит порог дома пракритасахаджии. Самые свободные, чистые вайшнавы никогда не будут участвовать в каком бы то ни было мероприятии, организованном пракрита-сахаджиями. Глупые люди думают, что в высшей степени освобожденные маха-бхагаваты поддерживают их греховную деятельность, но истинная цель Шри Гаурасундары и Его преданных – держаться в стороне от них, занятых греховной деятельностью, даже ценой обмана.',NULL),('cb.antya.2.272.ru','cb.antya.2.272','cb-ru','Услышав ответ Господа, радостный шакта ушёл. Таковы непостижимые качества Верховного Господа.',NULL),('cb.antya.2.273.ru','cb.antya.2.273','cb-ru','Все Веды провозглашают Кришну Патита-паваной, освободителем падших душ. Вот почему Господь говорил с этим шактой.',NULL),('cb.antya.2.274.ru','cb.antya.2.274','cb-ru','Потом люди скажут: "Этот шакта был освобождён, и другие шакты тоже получат освобождение, благодаря общению с Ним".',NULL),('cb.antya.2.275.ru','cb.antya.2.275','cb-ru','Таким образом, Господь Шри Гаурасундара использовал различные способы, чтобы освободить всех живых существ.',NULL),('cb.antya.2.276.ru','cb.antya.2.276','cb-ru','После шутливой беседы с этим шактой, Шри Гаурахари направился в деревню Ремуна.
В Шримад Бхагаватам Господь Вишну объясняет:
"Брахма, Господь Шива и Я – высшая причина материального проявления. Я, Сверхдуша, независимый свидетель всего. Но в безличном аспекте между Брахмой, Шивой и Мной – нет никакого отличия".
"Мой дорогой Дакша Двиджа, Я изначальная Личность Бога, но для того, чтобы создавать, поддерживать и уничтожать это космическое проявление, Я действую посредством Своей материальной энергии, и в соответствии с видами деятельности, Мои экспансии носят различные имена".
"Тот, кто не обладает достаточным знанием, считает независимыми таких полубогов как Брахма и Шива, или ещё хуже – считает независимыми живых существ".
"Человек среднего разума не думает, что голова и другие части тела могут существовать обособлено. Точно так же, Мой преданный не отрывает Вишну, всепроникающую Личность Бога, от всего прочего, или от любого живого существа". В Шримад Бхагаватам (2.4.18) сказано:
"Кираты, хуны, андхры, пулинды, пулкаши, абхиры, шумбхи, йаваны, представители племён кхасов и даже те, кто погряз во всех грехах, благодаря безграничному могуществу Господа могут очиститься, приняв покровительство Его преданных. Я склоняюсь перед Ним в глубоком почтении". В Шримад Бхагаватам (2.7.46) сказано:
"Души, предавшиеся Господу, даже если они принадлежат к тем, кто ведёт греховную жизнь: женщинам, рабочим, жителям гор или к коренным жителям севера, и даже звери и птицы, тоже могут постичь науку о Боге и вырваться из оков иллюзорной энергии, если предадутся чистым преданным Господа и будут следовать по их стопам, встав на путь преданного служения". В Шримад Бхагаватам (10.70.43) говорится:
"О Господь, слушая о Тебе, прославляя Тебя и размышляя о Тебе, очищаются даже неприкасаемые. Что же говорить о тех, кто видит Тебя и прикасается к Тебе?" Слово раса в этом стихе означает "шутить".
Ремуна находится в пяти милях к западу от Балазора. Там находится Божество Кшира-чора Гопинатхи.',NULL),('cb.antya.2.277.ru','cb.antya.2.277','cb-ru','Когда в Ремуне Господь увидел Свою собственную форму Гопинатхи, Он в восторге стал танцевать с преданными.
Махапрабху Сам танцевал перед Божеством Гопинатхи, обучая преданных этикету поклонения. Так как Шри Гопинатха является арча-виграхой Гаурасундары, тут было использовано словосочетание ниджа-мурти гопинатха – "Его собственная форма Гопинатхи". Шри Чайтаньядева и есть Гопинатха, сын Махараджи Нанды. Гаудия-натха и Гопинатха – имена, указывающие на Верховную Личность Бога. Они, соответственно, олицетворяют великодушие и сладостные игры, являясь одним целым. Форму Гаурасундары нельзя назвать отдельным проявлением Шри Гопинатхи.',NULL),('cb.antya.2.278.ru','cb.antya.2.278','cb-ru','Господь забыл Себя в Своей экстатической любви и безутешно разрыдался.',NULL),('cb.antya.2.279.ru','cb.antya.2.279','cb-ru','Даже камень и дерево смягчились бы, услышав эти горестные стенания и только сердца лицемеров не таяли.',NULL),('cb.antya.2.280.ru','cb.antya.2.280','cb-ru','За нескольких дней Шри Гаурасундара Махапрабху добрался до Брахмана-нагары, района Яджапуры.
Монумент со следами Шри Гаурасундары был установлен в храме Ади-Вараха, который находится в Брахмана-нагаре, окрестности Яджапуры. Этот монумент был создан и установлен владельцем села Балияти, Шрийуктой Мохини Моханом Райа Чоудхури Махашаей, в память о матери.',NULL),('cb.antya.2.281.ru','cb.antya.2.281','cb-ru','В этом месте есть замечательное Божество – Ади-Вараха. Приняв даршан этого божества, люди избавляются от всех материальных привязанностей.',NULL),('cb.antya.2.282.ru','cb.antya.2.282','cb-ru','Мимо этого места несёт свои воды самая сакральная из рек – Вайтарани. Все греховные реакции исчезают без следа при одном взгляде на эту реку.
Слово вайтарани в этом стихе указывает на реку Вайтарани. Деревня Яджапура, также известная как Набхи-гайа, находится на берегу этой реки в районе, известном как Вираджа-кшетра.',NULL),('cb.antya.2.283.ru','cb.antya.2.283','cb-ru','Если даже животное переплывает эту реку, полубоги смотрят на него как на четырёхрукую форму Господа.',NULL),('cb.antya.2.284.ru','cb.antya.2.284','cb-ru','Божество Вираджа-деви находится в Набхи-гайе, которая расположена в восьмидесяти милях от Джаганнатха Пури.',NULL),('cb.antya.2.285.ru','cb.antya.2.285','cb-ru','Я не смогу перечислить все храмы Яджапуры даже за сто тысяч лет.
Другое название Набхи-гайи – Вираджа-кшетра. Это место находится в пределах Яджапуры и в восьмидесяти милях от Нилачалы.',NULL),('cb.antya.2.286.ru','cb.antya.2.286','cb-ru','В Яджапуре находятся все виды храмов со всем многообразием божеств.',NULL),('cb.antya.2.287.ru','cb.antya.2.287','cb-ru','Драгоценный камень среди санньяси вместе с преданными в первый раз совершил омовение в Дашашвамедха-гхате.',NULL),('cb.antya.2.288.ru','cb.antya.2.288','cb-ru','После этого Господь с радостью посетил храм Ади-Варахи, где насладился экстатической любовью, танцуя и воспевая святое имя.',NULL),('cb.antya.2.289.ru','cb.antya.2.289','cb-ru','Господь был в восторге от Яджапуры и этот восторг постоянно и многократно возрастал.
Говорят, что Яджапура это искажённое название Йаятипуры, которая названа в честь Йаяти Кешари, шиваита и царя Ориссы. По мнению других, название Яджапура происходит от слова йаджнануштхана ("место жертвоприношения"), или от слова йаджана ("поклонение"). Махапрабху благополучно прибыл в Яджапуру в 1511
году нашей эры. Там же, в Яджапуре, находится храм Шри Варахадевы. Махапрабху провёл игры, предложив поклоны, пение и танцы Божеству Шри Варахадеве. Это описано в Шри Чайтаньячаритамрите (Мадхья 5.3-4):
"Шри Чайтанья Махапрабху и Его группа всё шли и шли, пока наконец не прибыли в Яджапуру на реке Вайтарани. Там Он увидел храм Варахадевы и предложил Божеству Свои поклоны. В храме Варахадевы, Шри Чайтанья Махапрабху пел, танцевал и возносил молитвы. Так Он провёл в храме всю ночь".
В Шри Чайтанья-чаритамрите есть упоминание о том, что Махапрабху приходил в Яджапуру ещё раз. В год, когда Шриман Махапрабху не согласился с Шрилой Гададхарой Пандита Госвами Прабху проживать в Нилачале, как санньяси, Шри Гаурасундара отправился в Яджапуру с Шри Раманандой Рая и двумя Махапатрами, Мангараджей и Харичанданой. В Яджапуре Махапрабху попрощался с двумя Махапатрами. (Смотри Шри Чайтанья-чаритамриту, Мадхья-лилу, главу шестнадцатую, стих 150).
Два каменных Божества Шри Варахадевы прикреплены друг к другу. Слева от Божеств есть каменное божество Шри Лакшми, и по левую сторону от него, Божество Шри Джаганнатхадевы. Перед ними находятся божества Лакшми-Варахи, которые чуть поменьше и отлиты из металла. От железнодорожного вокзала Яджапуры до храма Варахадевы – семнадцать миль, которые можно преодолеть, путешествуя тремя автобусами и переправившись паромом через две реки. На обоих берегах двух рек есть челночные автобусы, которые ожидают и перевозят пассажиров. Проехав девять миль в одном автобусе, путешественник переправляется через первый рукав Ямуны под названием Кхай. Затем придётся пройти шесть миль до следующей реки, называемой Буда. После переправы через неё, надо сесть на рейсовый автобус. В Яджапуре есть дхармашала, известная как Радхабаи дхармашала или Джаганнатха дхармашала. Это недалеко от древнего храма Джаганнатхи. Монумент со следами Шри Чайтаньи были создан в Яджапуре 25
декабря 1930
года. Для подробного изучения следует обратиться к изданию Гаудия, том 10, часть вторая.',NULL),('cb.antya.2.290.ru','cb.antya.2.290','cb-ru','Кто знает, каково было Его желание? Он неожиданно оставил всех позади и ушёл вперёд.',NULL),('cb.antya.2.291.ru','cb.antya.2.291','cb-ru','Когда преданные увидели, что Господа нет, они растерялись. Они пустились на поиски, проверяя все храмы.',NULL),('cb.antya.2.292.ru','cb.antya.2.292','cb-ru','Когда преданные нигде не нашли Господа, то сильно обеспокоились.',NULL),('cb.antya.2.293.ru','cb.antya.2.293','cb-ru','Нитьянанда сказал всем: "Успокойтесь, Я знаю, почему Господь ушёл".',NULL),('cb.antya.2.294.ru','cb.antya.2.294','cb-ru','"Господь хочет Сам посетить все святые места и храмы Яджапуры".',NULL),('cb.antya.2.295.ru','cb.antya.2.295','cb-ru','"Сегодня мы останемся здесь и соберём подаяние, а завтра увидим Господа".',NULL),('cb.antya.2.296.ru','cb.antya.2.296','cb-ru','Таким образом, все преданные отправились за подаянием, а потом все вместе поели.',NULL),('cb.antya.2.297.ru','cb.antya.2.297','cb-ru','Тем временем Господь обходил Яджапуру и посещал все святые места.',NULL),('cb.antya.2.298.ru','cb.antya.2.298','cb-ru','На следующий день Господь вернулся к ожидающим преданным.',NULL),('cb.antya.2.299.ru','cb.antya.2.299','cb-ru','Преданные тут же вскочили со своих мест и с энтузиазмом пропели "Хари! Хари!"',NULL),('cb.antya.2.300.ru','cb.antya.2.300','cb-ru','Прославив Яджапуру, славный Господь Гауранга уходя вместе со Своими спутниками запел имя Хари.',NULL),('cb.antya.2.301.ru','cb.antya.2.301','cb-ru','Таким образом, Шри Гаурасундара в большом экстазе путешествовал несколько дней, пока не прибыл в Каттаку.',NULL),('cb.antya.2.302.ru','cb.antya.2.302','cb-ru','После омовения в водах священной реки Маханади, Господь отправился в храм Сакши-гопалы.
Каттака расположена между рекой Маханади и Катджуди и является столицей Ориссы. Здесь был создан филиал Шри Чайтанья Матха, который называется Шри Саччид-ананда Матх. В храме регулярно поклоняются Божествам Шри Гаурасундары и Шри Виноды-рамана Джиу. В этом храме печатаются и распространяются различные духовные издания для преданных.',NULL),('cb.antya.2.303.ru','cb.antya.2.303','cb-ru','Увидев милую, очаровательную форму Сакши-гопалы, Господь громко взревел от экстаза.
Река Маханади протекает с северной стороны Каттаки. Во времена Махапрабху Божество Сакши-гопалы находилось в Каттаке. Затем, его перевезли в деревню под названием Сакши-гопала. После исчезновения Шри Махапрабху, это Божество было сначала доставлено в храм Джаганнатхи, а потом установлено в отдельном посёлке.
Это крупное Божество имеет четырёхрукую форму со всеми атрибутами. Старая история Сакши-гопалы описана в пятой главе Мадхья-лилы, Шри Чайтанья-чаритамриты.',NULL),('cb.antya.2.304.ru','cb.antya.2.304','cb-ru','Господь воскликнул: «Прабху!" и предложил поклоны и молитвы. Затем, в порыве любовного экстаза, Он разрыдался.
Когда Сакши-гопалу впервые привезли из Южной Индии и некоторое время хранили в Каттаке, оно было установлено на берегу реки Маханади. Затем, какое-то время Божество находилось в храме Джаганнатхи в Пурушоттаме. После каких-то неурядиц, царь Ориссы назначил новое место для Сакши-гопалы – деревню Сатявади в шести милях от Пурушоттамы. В настоящее время Сакши-гопале поклоняются во вновь отстроенном храме. Описания этого Божества можно найти в пятой главе Мадхья-лилы Шри Чайтанья-чаритамриты.',NULL),('cb.antya.2.305.ru','cb.antya.2.305','cb-ru','В форме Божества Верховного Господа, благодаря воспеванию Его святых имён проявилась духовная жизнь. Этот Господь теперь появился как Шри Кришна Чайтанья.
Способ взывания к одухотворённой форме Божества Верховного Господа, воспеванием маха-мантры, дарованной Шри Гаурой, практикуется в Шри-Гаудия сампрадайе. В отсутствие пения святых имён Господа, понятие того что арча-виграха – это кусок камня, продолжает иметь место. Нормы и правила для поклонения, которые учредил Шри Кришна Чайтаньядева, в соответствии с пониманием, раскрытом в стихе кришна-варнам твишакршнам, представляют собой радостное и надлежащее поклонение Божеству Господа, основанное на простом воспевании маха-мантры. Когда служение Господу имеет признаки физической обусловленности, или когда поклонение осуществляется чисто формально, тогда духовная жизнь в божестве не проявляется. Повторение Харе Кришна маха-мантры, которое проповедовал Шри Гаурасундара для поклонения, является самой одухотворённой формой милости.',NULL),('cb.antya.2.306.ru','cb.antya.2.306','cb-ru','И всё же, в этом воплощении Господь постоянно наслаждался играми в настроении преданного.',NULL),('cb.antya.2.307.ru','cb.antya.2.307','cb-ru','После этого Господь отправился в Шри-Бхуванешвару, к тому же известную как Гупта-каши. Там пребывает Господь Шанкара.
Описание святого места, Шри Бхуванешвары, встречается в различных писаниях, как Сварнадри-маходайа, Экамра пурана, Сканда пурана и других пуранах, написанных на санскрите. В этих источниках это место упоминаетя, как Бхуванешвара, Экамракакшетра, Хемачала и Сварнадри-кшетра.
По просьбе мудрецов, Бхагаван Вьяса раскрыл славу трудно достижимой Экамрака-кшетры. Название Экамрака-кшетра появилось по причине того, что когда-то, давнымдавно, на том месте росло огромное дерево манго. Там находятся десять миллионов лингамов Шивы и восемь тиртх. Это самое излюбленное место лучшего из вайшнавов – Шамбху, которое он почитает больше, чем Варанаси.
В штате Орисса, на южном берегу океана, течёт река Гандхавати. Эта река является рукавом Ганги. Трансцендентная обитель Экамрака-тиртха находится на берегу этой священной реки. Это место привлекательней, чем Кайласа.
Длина и ширина этой местности – три йоджаны (двадцать четыре мили). На восьми милях этого пространства поклонялись полубогам, а две мили земли находились в тени дерева манго. С незапамятных времён на этом месте благочестивые люди принимали омовение, читали мантры, совершали жертвоприношения, предлагали подношения, совершали абхишеку, предлагали поклонение, возносили молитвы, принимали прасад, слушали пураны, служили лотосным стопам преданных Господа и выполняли девять видов преданного служения.
В Сварнадри-маходайе сказано, что Господь Пурушоттама хранит это место. Вечный Верховный Брахман проявляет здесь Своё присутствие в форме лингама "Трибхуванешвары". В соответствии с утверждением, лингаят джнаяте ясмат, Верховный Брахман пребывает в Ориссе в форме лингама на священной золотой горе, окружённый полубогами. Поскольку хранит это место Сам Нараяна, вооружённый чакрой и палицей, Он является кшетра-палой, или его защитником.
К тому же, в Сварнадри-маходайе говорится, что Господь Шри Ананта Васудева лично защищает это место, вооружённый чакрой и палицей. Если первым делом не получить даршан Шри Ананты Васудевы, то благочестивая деятельность, не принесёт никаких плодов. Только те, кто твёрдо преданы Господу Шри Ананте Васудеве могут обрести милость Шри Бхуванешвары, который очень дорог Ананте.
Когда Бхуванешвара Бхагавати услышала из уст Шамбху о Экамрака-тиртхе, превосходящей своей славой Варанаси, она изъявила желание посетить это место. Тогда Шамбху сказал Бхуванешвари, "Сначала сходи туда сама, а я подойду и встречу тебя позднее". Получив разрешение мужа, она отправилась туда на своём льве и вскоре оказалась в Сварнадри. Там она воочию увидела, что это место приятней Кайласы. К тому же, она увидела огромный сверкающий чёрно-белый лингам. Бхуванешвари начала поклоняться этому великому лингаму со всеми предписанными атрибутами. Однажды Бхуванешвари собралась в соседний лес, чтобы нарвать цветов. Вернувшись, она увидела тысячу белоснежных коров, напоминающих цветы жасмина, которые вышли из озера и начали щедро омывать лингам своим молоком. Затем, обойдя вокруг линги, они вернулись туда, откуда вышли. Когда в следующий раз она увидела ту же картину, то приняв форму девушки-пастушки, она провела там пятнадцать лет.
Однажды в этот лес забрели два молодых брата-демона, Критти и Васа. Очарованные неповторимой красотой этой девушки-пастушки, они на своё горе стали грязно её домогаться.
Сати сразу же стала невидимой для взоров двух демонов и мысленно обратилась к лотосным стопам Шамбху. Как только Бхагавати вспомнила Махадеву, он тут же принял форму мальчика-пастушка и предстал перед Сати, пребывающей в форме гопи. Сати в образе гопи предложила поклоны Шамбху. Махадэва сказал: "О Сати, я понимаю, почему ты вспомнила меня. У тебя нет никаких оснований для тревог. По воле Верховного Господа эти два демона задумали недоброе по отношению к тебе, чтобы призвать собственную смерть. Позволь мне рассказать тебе эту историю. Когда-то жил-был царь по имени Друмила, который к радости полубогов совершил множество жертвоприношений. Полубоги благословили его, и обещали, что у него будут два сына с именами Критти и Васа, которых нельзя будет убить никаким видом оружия. Так что теперь, по воле Верховного Господа, ты должна будешь убить этих двух грешных демонов".
Получив указание супруга, Сати в образе девушки пошла бродить по лесу и в скором времени встретила этих двух братьев. Чтобы ввести их в заблуждение и сбить с толку, Сати сказала: "Я могу исполнить ваши желания, но при одном условии. Я буду принадлежать тому, кто сможет поднять меня и пронести на плече".
Услышав условие Сати, два опьянённых брата затеяли между собой ссору. Затем Сати, пребывающая в образе гопи, села на плечи братьев, положив одну ногу на плечо Критти, а другую – на плечо Васу и приняла форму Вишвамбхари. У кого хватит сил вынести тяжкое бремя Вишвамбхари? Под весом Сати, оба демона были смяты и раздавлены. Это событие, описанное в пуране, заканчивается тем, что с того времени Сати и её супруг Шамбху, оставили свой золотой храм в Каши и стали жить в лесу Экамрака.',NULL),('cb.antya.2.308.ru','cb.antya.2.308','cb-ru','Шива собрал по капле воды из всех святых мест и создал озеро, известное как Бинду-саровара.
После убийства двух демонов, Критти и Васы, Бхуванешвари в форме девушкипастушки, от жажды впала в сонливость. Чтобы утолить жажду Бхуванешвари, Махадева пронзил гору наконечником своего трезубца и сделал водоём, который известен как Шанкара-вапи, или водоём господа Шивы. И всё же, Бхуванешвари пожелала напится воды из освящённого водоёма. Тогда Шамбху послал своего Быка принести воду из всех священных мест и позвал Брахму освятить водоём проведением жертвоприношения. Все приглашённые Быком полубоги во главе с Брахмой, собрались в этом месте и предложили свои поклоны Бхуванешваре. Затем Бык принёс воду из Мандакини и других небесных источников; он принёс воду из Праяги, Пушкари, Ганги, Гангадвари, Наимиши, Прабхасы, Питри-тиртхи, Ганга-сагара-сангамы, Пайошни, Випаши, Шатадры, Кавери, Гомати, Кришны, Ямуны, Сарасвати, Гандаки, Ршикульи, Маханади и других земных источников; он принёс воду из молочного океана и других источников, вплоть до Паталы. Когда Бхуванешвара увидела все олицетворённые тиртхи, собравшиеся в этом месте, он поднял трезубец и пронзив им гору сказал, "В этом месте я решил создать озеро. Пусть все присутствующие предложат по капле своей воды этому озеру". Когда тиртхи исполнили указание Шамбху, Господь Джанардана и полубоги, возглавляемые Брахмой, совершили в озере омовение. Бхуванешвара со своими последователями тоже с радостью окунулись в эти воды. Бхуванешвара сказал: "Отныне здесь будут два чистых водоёма, Шанкара-Вапи и Бинду-саровара. Тот, кто совершит омовение в Шанкара-Вапи, обретёт качества, которыми обладаю я, а омывшись в водах Бинду-саровара, он достигнет моей обители".
После этого лучший из вайшнавов, Шамбху, предложил свои поклоны Джанардане и сказал: "О, Пурушоттама, будь милостив, поселись здесь вместе с Анантой, на восточном берегу этого озера, в форме двух Божеств, и как мои повелители, защитите эту обитель". С тех пор Господь Ананта Васудева благословил дорогого Шанкару, отдав ему остатки Своей трапезы и поселился на восточном берегу Бинду-саровары, как повелитель Шамбху и защитники этой обители. Таким образом, там поклоняются Бхуванешваре Шамбху, с предложениями остатков еды Шри Шри Ананты-Васудевы.
В Сварнадри-маходайе сказано, что озеро Бинду-саровара, также известно как Маникарни, и в нём духовная сила всех тиртх. Если человек получит даршан Шри Ананты Васудевы после омовения в Маникарни, высшей из всех тиртх, он безусловно отправится на Вайкунтхалоку. Подношения, предложенные брахманам и вайшнавам в этом месте, приносят плоды в сто раз превосходящие плоды от посещения других святых мест, а предложение предкам прасада Шри Ананты Васудевы, доставляет им огромное удовольствие. Омовение в озере Бинду-саровара, приравнивается к благу, полученному от омовений во всех святых местах. Даршан Шри Ананты Васудевы после совершения омовения, приносит не имеющие себе равных плоды.
Праздники посвящённые Шри Шри Ананте-Васудеве, Чандана-ятра Шри Шри Мадана-мохана и праздник с играми на лодках – все собраны в водах Бинду-саровары.
Древний храм Шри Ананты Васудевы как и прежде находится на восточном берегу Бинду-саровары. Этот храм прекрасно украшен. Божество Шри Ананты Васудевы Вишну было установлено в этом грандиозном храме, украшенном чудесными образцами изобразительного искусства и архитектуры, Шри Бхавадевой Бхаттой, жителем Сиддхала-грамы. Царём из династии Саварна были отданы в дар сведущим брахманам много деревень.
Сиддхала-грама – лучшая из них. Тут приняли рождение три великие души – Махадева, Бхавадева (первый) и Аттахаса. Из них, особо прославился и стал знаменитым Бхавадева. Он получил в дар от царя Гауды село Хастини. У него было восемь сыновей во главе с Ратхангой. Сыном Ратханги стал Атьянга, сыном Атьянги стал Будха, а сыном Будхи – Адидева, который стал премьер-министром царя Гауды. Сын Адидевы Говардхана женился на девушке из семьи Бандьягхатья. Из её лона родился Бхавадева второй. Этот Бхавадева был весьма сведущим в тантре, математике, астрологии и Аюрведе. Книги по астрологии, логике и мимамсе, написанные им, стали известными в среде учёных. Бхавадева был советником царя Харивармадевы, благодаря чему он и его сын долгое время наслаждались царским правлением. Этот Бхавадева Бхатта в различных местах Радха-деши построил много водохранилищ, которые к нашему времени почти все высохли. Именно он воздвиг храм и установил там Божество Шри Ананты Васудевы Вишну, и поддерживал чистоту Бинду-саровары, проводя дноочистительные работы. Ему присвоен титул Бала-валлаабха-бхуджана. Эти сведения о династии Бхавадевы Батты высечены на каменной плите в храме Шри Ананты Васудевы. Поэт по имени Шри Вачаспати, дорогой друг Бхавадевы, описал все события в стихах. Этот камень с надписью хранился в храме до середины девятнадцатого века. После, полковник Кито Сахеба перенёс текст с этого камня, описывающем Мегхешвару, на стену храма Шри Ананты Васудевы. Размеры этой надписи – два локтя и два дюйма в длину и один локоть, один дюйм в ширину (локоть приблизительно равен полутора дюймам). Надпись на камне состоит из двадцати пяти строк, а каждая буква – высотой около половины дюйма.
В шестой и седьмой главах Сварнадри-маходайи, Махадева говорит: "О, Брахма, ты вместе с другими полубогами должен прийти в лес Экамрака и провести поклонение древней линге с различными трансцендентными атрибутами. Завершив поклонение вы должны с верой почтить остатки своих предложений".
Выслушав указание Махадевы, Брахма спросил, "О Махешвара, мы не знаем, насколько ты славен. Мудрецы говорят, что остатки предложения линге не заслуживают почтения. Так как же мы можем принять эти остатки?"
Вьяса сказал: "Несмотря на то, что остатки предложения линге принимать не следует, Шри Бхуванешвара – не линга, а вечный Верховный Брахман. Предписания, которые запрещают почитать остатки подношений Шиве, не применимы к Бхуванешваре. Полубоги почтили прасад Бхуванешвары, чтобы преодолеть материальный океан. Продукты питания, предлагаемые Бхуванешваре, следует принимать с пониманием того, что они трансцендентны. Прасад Бхуванешвары могут принимать все без исключений, брахманы, кшатрии, вайшьи, шудры и неприкасаемые, а противники этого – неизбежно проследуют в ад. Получив прасад Бхуванешвары, следует немедленно его почтить. Прасад Бхуванешвары никогда не оскверняется, даже от прикосновения нечистых живых существ. Надо раздавать и предлагать этот прасад полубогам, предкам и брахманам. Благо от распространения прасада Бхуванешвары не уступает плодам, обретаемым от посещения Курукшетры во время солнечного или лунного затмения. Независимо от того, остатки сухие, чёрствые или они долго были в пути, почитание прасада Бхуванешвары избавляет от всех скверных привычек.
Почитая прасад Бхуванешвары человек обретает плод, равный благу, получаемому от созерцания, поклонения, медитации или от слушания повествований о славе Вишну. Даже питаясь одним нектаром, можно родиться снова, но больше не придётся принимать рождение тому, кто почтит прасад Бхуванешвары. От одного вида прасада Бхуванешвары исполнятся все желания зрящего; лишь поднеся его к голове, человек уничтожает все свои греховные реакции; лишь почитая его, человек избавляется от последствий приёма нерастительной пищи; один запах такого прасада уничтожает грехи, совершённые мысленно; один взгляд на него открывает духовное видение; намазывание им очищает всё тело; почтительное вкушение такого прасада даёт плод, достигаемый от соблюдения экадаши без воды; прославляя его с глубоким почтением, человек обретёт преданное служение Вишну".
Мудрецы продолжали вопрошать, а Вьяса рассказывать: "В Брахманда пуране Брахма говорит Нараде, "Что говорить о людях, если даже полубоги, возглавляемые Брахмой, принимают формы людей, чтобы получить прасад Бхуванешвары. Для приёма прасада Бхуванешвары нет никаких правил или ограничений по времени. Если человек примет прасад Бхуванешвары, которого коснулся самый ужасный из грешников, он обязательно достигнет обители Вишну. Тот, кто осуждает прасад Бхуванешвары и сравнивает его с обычными остатками предложений Шива-линге, непременно отправится в ад. Гаури, величайшая из вайшнави, готовит предложение Бхуванешваре, а вечный Верховный Брахман принимает предложенное. Поэтому не может быть и речи о осквернении контактом с нечистыми живыми существами. Необходимо знать, что эти остатки полностью трансцендентны. Если остатков еды Шри Ананты Васудевы и маха-маха-прасада Шри Бхуванешвары коснётся язык собаки, или они будут принесены из места хранения, где находились вместе с продуктами нерастительного происхождения, их следует принимать даже самым возвышенным из брахманов. Употребляя в пищу эти остатки, предложенные трансцендентной линге, человек найдёт прибежище у Господа Вишну, а это редкая удача, о которой мечтают такие личности как Брахма и Индра. Те, кто оскорбляют преданных, вкушающих этот маха-прасад, будут жить в аду, пока солнце и луна сияют в небе. Независимо от того, совершил человек омовение или нет, просто почитая маха-прасад Бхуванешвары, он очищается внешне и внутренне. Своими тысячами уст даже Анантадева не в состоянии описать славу этого маха-маха-прасада – остатков трапезы Шри Ананты Васудевы. Можно порадовать Бхуванешвару просто слушая о славе этого прасада, и если Бхуванешвара будет удовлетворён, довольным останется и Говинда".
Каждый день, совершив поклонение и сделав предложение Шри Шри Ананте Васудеве, Шри Бхуванешвара сам принимает поклонение и подношения. Эта система попрежнему действует в Бхуванешваре. Помимо этого, он учит преданному служению Вишну людей всего мира, учредив правила отказа от материальных наслаждений ради удовлетворения Кришны и собственным примером показывает как им следовать. Он сам не ездит на колеснице, и не прогуливается во время фестиваля Чандана-ятра, и не катается на празднике лодок, но предлагает эти средства передвижения и другие благостные атрибуты поклонения своим вечным повелителям, Шри Ананте-Васудеве и Шри Шри Мадана-мохану. Всякий раз, когда упоминается, что Шри Бхуванешвара передвигается на летательном аппарате или на колеснице, следует понимать, что целью всех таких перемещений является желание удовлетворить Шри Мадана-мохана и Шри Ананту-Васудеву.
Панды (священники) из Бхуванешвары называют Шри Мадана-мохана – пратинидхи или "представителем" Бхуванешвары. В этом контексте слово "представитель" не означает подчинённый, в обычном понимании, как в отношениях между царём и его служащим. Исходя из положения шакти-таттвы, Шри Бхуванешвара лично не принимает какие-либо подношения ради собственного удовольствия, а предлагает их своему единственному Господу, в высшей степени независимому Шри Мадана-мохану, который является источником всех энергий и собственником всех объектов наслаждений. Другими словами, так как он не является независимым наслаждающимся, и вместо этого делает всё ради удовлетворения своего Господа, Господь относится к нему, как к Своему "представителю". Вместо того, чтобы принимать поклонение себе, Бхуванешвара принимает поклонение от имени своего Господа, Шри Мадана-мохана и Шри Ананты-Васудевы. Даже если он когда-либо и принимал служение себе, то делал это как слуга Шри Маданамохана или Шри Ананты-Васудевы. Он не независим, и не принимает какого-либо служения для собственного удовольствия.
Божество Шри Мадана-мохана, пребывающее в Шри-Бхуванешваре имеет не двурукую, а четырёхрукую форму. Верхняя левая рука Мадана-мохана изображает лань, в верхней правой руке – топор, Его нижняя левая рука изображает жест бесстрашия, а нижняя правая рука изображает благословение. Шри Мадана-мохану, Шри Говинде, пятиглавому Махадеве, виджая-мурти Шри Ананты-Васудевы, четырёхрукой форме Харихара мурти, и Шри-Шалаграме поклоняются в храме к югу от изначального храма Бхуванешвары.
Комитет ответственных попечителей, поддерживающих служение в храме Шри Бхуванешвары представляют: Шриюкта Приянатха Чаттопадхьяйа, адвокат из Каттаки, Шриюкта Гангадхара Чаудхури, землевладелец из округа Пури и Шриюкта Гопала Прахарараджа, тоже адвокат из Каттаки. Комитет в этом составе нанял управляющего по имени Шриюкта Лачман Рамануджа даса. Управляющий контролирует доходы и расходы, и обеспечивает различное служение и поддержание храма Бхуванешвары с помощью следующих четырёх старших пандов: Джаганнатхи Махапатры, Нараяны Макадамы, Дамодары Сантары и Садайа Махапатры.
У ворот льва в храме Шри Джаганнатхи, ради блага падших душ, не входящих в систему варнашрамы, установлено мурти патита-паваны. У ворот льва в храме Бхуванешвары тоже есть мурти патита-паваны. У ворот льва находится рынок, известный как Ананда-базар. Как и в Пури, на Ананда-базаре тоже продают прасад. Прасад Джаганнатхи не оскверняется при контакте с грешными живыми существами. За воротами льва находится колонна, Гаруда-стамбха, на вершине которой скульптуры Быка и Гаруды. У входа в храм, как и в храме Джаганнатхи, также установлено Божество Нрисимхадевы. Это четырёхрукое божество Нрисимхи изображает умиротворённое настроение. В правой верхней руке Божество держит чакру, в верхней левой руке – раковину, а в двух нижних руках Нрисимхадева держит Веды. Шри Лакшмидеви сидит у Него на коленях. Южнее старого храма расположена кухня. Существует распоряжение, что лучи солнца и луны не должны проникать туда. Еду здесь готовят брахманы панды из трехсот шестидесяти семей. Божество Шри Бхуванешвары главного храма представляет собой совместную форму Шри Хари и Хары. Панды всем дают возможность увидеть это Божество Шри Бхуванешвары, окрашенное в черный и белый цвета. Божество Шри Бхуванешвары имеет форму чакры с изображениями Ганги, Ямуны, Сарасвати и десяти воплощений, начиная с Матсьи и Курмы.
Прекрасно художественно оформленный храм Бхуванешвары завораживает простых людей, которые приходят на даршан. Глядя на мастерство и искусность архитектурных решений храма Бхуванешвары, храма Шри Ананты-Васудевы, и многих других храмов в местности Бхуванешвара, можно прочувствовать, на сколько высоко развитым было индийское искусство того времени. Высота храма Бхуванешвары – сто шестьдесят пять футов. Этот храм построен на огромной каменной плите, и расположен в трёхстах ярдах к югу от Бинду-саровары. Размеры храма – пятьсот двадцать четыре фута в длину и сто шестьдесят пять футов в ширину. Отдельно от основного здания, к северу от храма есть внешний зал в двадцать восемь футов. Главный зал – двести тридцать пять футов в длину. Толщина стен храма – семь футов и пять дюймов. С каждой из четырёх сторон храма находятся большие ворота. Восточные ворота самые большие из четырёх и называются Симха-двара, или ворота Льва. По обе стороны от входа установлены два больших льва. Внутренний двор имеет длину двадцать футов, и обнесён стеной из каменных плит, высотой в четыре фута. Эта нерушимая каменная стена была построена для защиты храма от нападения извне. Божество Шри Нрисимхадевы расположено у одной из сторон этой стены. На западном внутреннем дворе расположились многочисленные маленькие храмы Шивы. Среди этих храмов есть один, высотой в двадцать футов. Этот маленький храм древнее главного храма. Его алтарь расположен на пять футов ниже уровня пола главного храма. Говорят, что Шива-лингам установленный здесь – самый древний. Даже после того, как было закончено строительство главного храма, старый лингам остался в малом храме. В одном из углов западного двора есть храм Бхуванешвари. С одной стороны от ворот Симха-двара, есть массивная каменная платформа, которую можно увидеть зайдя внутрь двора. На ней храм Гопалини – Сати в образе девушки-пастушки. Хотя уровень пола храма Гопалини ниже уровня главного храма, он находится на одном уровне с храмом лингама Шивы. К западу от храма Гопалини есть шесть каменных ступенек. Над этими ступенями и ниже кухни Бхуванешвары стоит божество Вришабхи, быка Шивы.
Бхога-мандапа, или место где делают подношения, находится прямо перед храмом Бхуванешвары. Дальше находится натья-мандира (место проведения спектаклей, танцев и киртана), за натья-мандирой расположилась джагамохана (площадка прямо перед центральным алтарём), ещё дальше находится главный храм, и примыкает к нему гарбха-гриха – место где находится божество. Из заключений Раджи Раджендралала Митры следует, что бхога-мандапа была построена во время правления Камалы Кесари, которое длилось с 792
г. н.э. по 811
г. н.э. Другие археологи утверждают, что это место предложений, за двадцать четыре года своего правления, построил царь из династии Ганги – Нарасимхадева, который возвёл храм Солнца в Конарке. Изучив надпись на дверях натья-мандиры, можно узнать, что Махараджа Капилендрадева, который завоевал Карнатаку, организовал сбор пожертвований для покупки обширного участка земли, для служения Бхуванешваре. По мнению большинства археологов, натья-мандира была построена за много лет до правления Капилендрадевы. Раджа Раджендралала Митра склоняется к мнению, что эту натья-мандиру построила царевна Шалиникешари между 1099
и 1104
годами н.э., но многие археологи с ним не согласны. Справа от входа в комнату божества есть надпись, которая гласит, что Нарасимхадеви построила Храм Солнца в Конарке и эти ворота. Конечно же, Натья-мандира и вход в храм Бхуванешвары, это славная работа доблестных царей династии Ганги. Поскольку в надписи упоминается имя дочери царя, многие склонны думать, что строительство – дело рук дочери царя из династии Ганги. Некоторые полагают, что дочь этого царя была упомянута в календаре Мадала-панджи, как царевна Шалиникешари.
Мастерство, художественное исполнение и архитектура джагамохана – просто потрясают. Крыша джагамохана, как и крыша зала для предложений, по форме напоминает остроконечную вершину. Эта крыша поддерживается четырьмя гигантскими, в тридцать футов высотой, каменными столбами. Слева от его южного входа есть прямоугольная, прекрасно архитектурно украшенная комната, но строители этой комнаты по каким-то причинам не смогли завершить работу. В этой комнате несколько бронзовых божеств. Это виджайа-мурти Бхуванешвары. Их вывозят из храма во время фестивалей. Высота храма Бхуванешвары от земли до каласы – сто шестьдесят футов, но так как уровень пола комнаты божеств на два фута ниже уровня нового фундамента, то соответственно и восточный двор тоже ниже общего уровня на два-три фута. Так, в прежнее время, высота до вершины должна была достигать ста шестидесяти пяти футов.
Помимо храма Шри Лингама Бхуванешвары и храма Шри Ананты-Васудевы, есть много других храмов, расположенных по всей округе. Как уже было сказано, высота храма Бхуванешвары – 160
футов от уровня земли до пика. Высота храма Ананты Васудевы – 60
футов, храма Рамешвары – 78
футов, высота Йамешвары составляет 67
футов, Хаджарани – 63
фута, высота Бхагавати составляет 54
фута, Шаридеула – 53
фута, Нагешвары – 52
фута, Сиддхешвары – 47
футов, Капилешвары – 64
фута, Кедарешвары – 46
футов, Парашурамешвары – 38
футов, Муктешвары – 35
футов и Копари – 35
футов в высоту.
Многие думают, что храм Бхуванешвары древнее храма в Джаганнатха Пури и что художественное оформление храма в Пури, это имитация архитектуры храма в Бхуванешваре.
Раджа Раджендралала Митра сказал, что царь Йаяти Кешари пришёл из Магадхи, выгнал яванов, и восстановил индуизм, уничтожив буддийскую веру. Продолжительность правления Йаяти Кешари – с 474
по 526
годы нашей эры. Строительство храма Бхуванешвары и джагамоханы началось в конце правления Йаяти Кешари, но завершить строительные работы он не смог. Хотя его потомок Сурья Кешари правил царством в течение длительного времени, он не попытался завершить строительство храма. Его наследник, Ананта Кешари, возобновил строительство храма. В конце концов, строительство храма Бхуванешвары было завершено во время правления Лалатенду Кешари в 588
году эпохи Шакабда (666
год н.э.). По поводу этого события, Раджа Раджендралала Митра процитировал следующий стих:
И всё же, не все археологи согласились с утверждением Махашайи Митры. Они говорят что надпись найденная на камне, похожа на рукописный стих, описывающий строительство храма Джаганнатхи и не имеет документальных исторических подтверждений. К тому же, они утверждают, что в своём описании Раджа Раджендралала Митра, цитируя календарь Мадала-панджи Джаганнатхи, пытался как представитель панд, знающих исторические факты, доказать, что это святое место более древнее, чем на самом деле. Точная дата строительства храма Бхуванешвары и джагомахана находится на камне с высеченной надписью, которая повествует о начале строительства. Знаменитый Анангабхима, который является строителем храма Шри Пурушоттама, также упомянут в этой надписи на камне, как строитель храма Бхуванешвары. На этом камне описаны тридцать четыре года жизни Ананги-бхимы. В надписи на камне в Чатешваре и в царских записях на медной пластине Нарасимхадевы второго, упомянуты два имени, Ананга-бхима и Анийанка-бхима. Ананга-бхима Первый, был четвёртым сыном Кауда Ганги. Он правил царством в течение десяти лет. Он завоевал Ориссу и построил храм Шри Пурушоттамы. Второй Ананга-Бхима был внуком первого Ананги-Бхимы и сыном Раджараджи. Он царствовал тридцать четыре года, вплоть до 1253
года нашей эры. Поскольку надпись на каменной плите в храме Бхуванешвары упоминает тридцать четыре года правления, связанные с Анийанка-бхимой, сыном Раджараджи, некоторые археологи считают фактическим строителем храма Бхуванешвары второго Анийанка-бхиму или Ананга-бхиму. Этот второй Анийанка-бхима построил много больших храмов в Каттаке и других местах – в Пури и Ганджаме.
Мы уже затрагивали тему храма Ананты Васудевы, расположенного на восточном берегу Бинду-саровары перед средней гхатой. Высота этого храма – сто тридцать один фут, а длина – сто семнадцать футов. Главный зал – девяносто шесть футов в длину и двадцать пять футов в ширину. К главному зданию храма примыкает джагамохана, за которой расположена натья-мандира, и ещё дальше – бхога-мандапа. От основания до вершины храма, каласы – шестьдесят футов. Внутри натья-мандиры установлено божество Гаруды, выполненное из чёрного камня. Божество Ананты Васудевы Вишну находится в главном храме. Храм Ананты Васудевы является самым древним храмом в Бхуванешваре. Этот факт общепринят даже среди археологов. Никто из паломников не начинает поклонение Шри Васудеве, предварительно не приняв даршан Ананты Васудевы Вишну, Господа всех. Эта практика поклонения соблюдается в Бхуванешваре по сей день. Мы уже знаем из стихов поэта Вачаспати Мишры, написанных на каменной плите, прикреплённой к стене храма Ананты Васудевы, что Бхавадева Бхатта построил храм Ананты Васудевы и благоустроил озеро Бинду-саровара, которое расположено перед храмом. Вачаспати Мишра написал книгу Ньяйа-шучи-нибандха в 898
году эпохи Шакабда (976
год н.э.). Не следует считать его современником и другом Бхавадевы Бхатты. Поэтому некоторые археологи приходят к выводу, что храм Шри Ананты-Васудевы был построен в десятом веке.
Бинду-саровара имеет тринадцать сотен футов в длину, семь сотен футов в ширину и шестнадцать футов в глубину. Четыре берега озера саровары покрыты каменными плитами. На середине Бинду-саровары есть остров, построенный из камня. Площадь острова – сто на сто футов. В северо-восточном углу острова есть маленький храм. На фестивале Снана-ятра, в честь Божества Ананты Васудевы, Божество привозят в этот храм. Здесь Божество купают в струях воды, брызжущих из окружающих этот храм фонтанов. Во время Снана-ятры, во время сезона дождей, Бинду-саровара становится пристанищем больших крокодилов.
Западные историки, такие как Старлинг, Хантер и Каннингем, а также такие археологи Индии, как Раджа Раджендралала Митра, описывают Бхуванешвару, как центр буддизма. Тем не менее, другие археологи Индии приводят аргументы и доказательства, такие как надписи на каменных плитах, найденных в различных храмах Бхуванешвары и описания древних пуран, таких как Махабхарата, и на основании этого утверждают, что это место не может быть центром буддистской культуры. Доказательства присутствия тут буддизма, найденные в Кхандагири и Удаягири, относятся к более поздней эпохе, и не имеют отношения к временам Будды. Рекламная история о том, что пещера Слона – это буддистская пещера, давно и уверено опровергнута, а сама идея принадлежит джайнистам и основывается на том, что в этой пещере была найдена каменная плита с надписью, прославляющей царя Ориссы Кхарбела Бхупати, который был последователем религии джайн. Но нет никаких доказательств или свидетельств точной даты того, когда джайнист Кхарбел обосновался в столице Бхуванешвары. В 114
главе Вана-парвы Махабхараты сказано, что в районе Калинги, в месте слияния – Ганга-сагаре, есть священная река Вайтарани, а Йаджапура где Брахма совершил жертвоприношение, находится на берегу этой реки. Далее, находится область Сваямбху-Вана, а затем, уже ближе к океану – Махаведи, известная как Пурушоттама-кшетра. После этого начинается подножие горы Махендра, которая находится в округе Ганджама, и это место известно как обитель Парашурамы. Вышеупомянутое имя Сваямбху относится к Шамбху или Махадеве. Это заключение приводится в древнем комментарии к Махабхарате, известном как Дургатартха-пракашини. Очень долгое время Сваямбху-вана была местом пребывания отшельников и отречённых. В Сканда Пуране, Уткала-кханде сказано:
"Это святое место в давние времена было создано Махадевой. Тут Брахма собственноручно установил божество супруга Парвати. С тех пор это место прославилось как любимое место Шамбху, уничтожающее невежество. Это место имеет и другое название – Экамрака-вана или Экамрака-кшетра".
В другом месте Уткала-кханды Сканда Пураны, сказано:
sa vartate nilagirir yojane ''tra trtiyake idam tv ekamraka-vanam ksetram gauri-pater vidhuh catur deha sthito ''ham vai yatra nilamani-mayah tasyottarasyam vikhyatam vanam ekamrakahvayam
Экамрака-канана, которая так дорога супругу Парвати, расположена в двух йоджанах к северу от Нилачалы – в стране Орисса. Эта Экамрака-кшетра является Сваямбхуваной, описанной в Вана-парве Махабхараты, и многие вдумчивые люди пришли к выводу, что это место намного древнее эпохи Будды.
Описание Шри Бхуванешвары-девы приводится в Капила-самхите. Давным-давно в Каши, Господь Вишвешвара (Шива) попросил деварши Нараду покинуть Каши, потому что этот город будет вскоре духовно уничтожен приносящими беспокойство атеистами, погрязшими в мирских знаниях. Там будут разрушены все религиозные принципы и каждый станет неверующим. Кроме того, население Каши постепенно увеличится, и там не будет возможности соблюдать аскезы. Хотя Махадева приложил много усилий, кропотливо создавая Каши для удовольствия Парвати, она больше не сможет оставаться там изза беспокойств, созданных атеистами. Где же найти то место, где можно было бы спокойно сосредоточиться и поклоняться вечной Верховной Личности Бога? Услышав эти слова Шамбху, лучший из вайшнавов, деварши Нарада сказал, что есть славная гора Нилачала, расположенная на берегу солёного океана. К северу от этой горы находится благоприятный лес Экамрака-канана. Васудева, Господь Лакшми, вместе с Анантой живёт как отшельник в этом священном лесу. Это самое сакральное место. Услышав ответ Нарады, Махадева оставил Каши и вместе с Парвати отправился в Экамрака-вану. Когда Махадева пришёл в священный лес, он сказал Шри Хари, "Я пришёл, чтобы найти у Тебя приют. Пожалуйста, дай мне место, чтобы быть рядом с Твоими лотосными стопами". Выслушав просьбу Шамбху, лучшего из вайшнав, Шри Васудева ответил: "О Шамбху, Я с удовольствием позволю тебе остаться, но обещай Мне, что никогда не вернёшься в Каши". Тогда Шанкара ответил, "Как я могу навсегда оставить Каши? Мои возлюбленные Джахнави
(Ганга) и Маникарника, средоточие всех святых мест, остались там". Васудева сказал: "О Шамбху, здесь предо Мной находится Маникарника, которая ещё известна как Папанашини. Река Ганга-Ямуна, которая исходит из Моих лотосных стоп, несёт свои воды к юговостоку от Меня. Тут много других священных тиртх". Тогда Шанкара ответил: "Я обещаю, что не оставлю Твои лотосные стопы и никуда не уйду, даже в Варанаси". После этих слов, Шамбху остался к югу от Вишну в форме Линги. Этот тёмно-синий лингам светится как кристалл, и известен как Трибхуванешвара, или Бхуванешвара.
Панча-кроша Бхуванешвара парикрама выполняется в месяц Картика. Процессия двигается из Варахадеви, проходит через Дхавалагири, Кхандагири, Удаягири, вокруг железнодорожной станции Бхуванешвара, и в конечном итоге возвращается в храм Варахадеви.
Бхуванешвара находится в 272
милях от Ховры, станции железной дороги Бенгалия – Нагпур. Храм Бхуванешвары находится в двух милях от одноимённой станции. Дорога эта очень хорошая и с обеих сторон её украшают горные деревья, такие как кунчила и нукс вомика. Самый распространённый транспорт, это повозка запряжённая волами, хотя можно ехать и на автобусе, или легковом автомобиле. В Бхуванешваре есть две дхармашалы. На берегу Бинду-саровары, некто Калькутта Марвари, по прозвищу Хазаримала, построил новую большую дхармашалу. Другую дхармашалу соорудил некий Райа Бахадур Харговинда Вишвешваралала. Паломники могут остановиться в этих дхармашалах на несколько дней. Там есть благотворительная больница, телеграф и почтовое отделение. Каждый понедельник и четверг работает открытый рынок, на котором можно приобрести прасад Джаганнатхи, Шри Ананты Васудевы и Бхуванешвары.',NULL),('cb.antya.2.309.ru','cb.antya.2.309','cb-ru','Зная как это озеро дорого Шиве, Шри Чайтанья с огромным благоговением принял в нём омовение, и увеличил его славу.',NULL),('cb.antya.2.310.ru','cb.antya.2.310','cb-ru','После этого Господь отправился посмотреть на олицетворение Шанкары, последователи которого пели ему славу со всех сторон.',NULL),('cb.antya.2.311.ru','cb.antya.2.311','cb-ru','Кругом стояли ряды светильников с гхи, а Шива-лингу непрерывно омывала вода.',NULL),('cb.antya.2.312.ru','cb.antya.2.312','cb-ru','Господь и все вайшнавы были рады видеть, как славят дорогого преданного – Шанкару.',NULL),('cb.antya.2.313.ru','cb.antya.2.313','cb-ru','Шива забывал об одежде, наслаждаясь экстазом служения лотосным стопам Верховного Господа, но сейчас этот Господь Сам танцевал перед ним.',NULL),('cb.antya.2.314.ru','cb.antya.2.314','cb-ru','После радостных танцев и пения в честь Шивы, Гаурачандра остался на ночь в этой деревне.',NULL),('cb.antya.2.315.ru','cb.antya.2.315','cb-ru','Теперь я расскажу историю из Сканда Пураны, как Шива оказался в этом месте.',NULL),('cb.antya.2.316.ru','cb.antya.2.316','cb-ru','Долгое время Шива и Парвати жили в уединенном месте в Каши.',NULL),('cb.antya.2.317.ru','cb.antya.2.317','cb-ru','Когда Шива отправился с Гаури на Кайласу, цари людей стали правителями Каши.',NULL),('cb.antya.2.318.ru','cb.antya.2.318','cb-ru','Один царь, по имени Кашираджа, поклонялся Шиве, наслаждаясь богатствами Каши.',NULL),('cb.antya.2.319.ru','cb.antya.2.319','cb-ru','По воле провидения и времени, он стал поклоняться Шиве, совершая суровые аскезы, ради того, чтобы победить в бою Кришну.
История царя Каши Судакшины, так описана в шестьдесят шестой главе десятой песни Шримад Бхагаватам:
В то время как Господь Баладева был в гостях у Нанды во Врадже, царь Паундрака из Каруши, поощряемый глупцами, провозгласил, что он истинный Васудева и сообщил Верховной Личности Бога Васудеве, что никто другой, кроме него не может быть Васудевой, и поэтому Шри Кришна должен отказаться от имени и эмблемы Васудевы и покорится Паундраке. В противном случае, он вызовет Господа на битву. Когда Уграсена и члены его царского собрания услышали глупое хвастовство Паундраки, они все долго и от души хохотали. Шри Кришна передал посланнику Паундраки, что Он скоро даст возможность глупому царю принять Его символы, как Сударшана чакру, которые пока находятся у Него, а его тело, после того как он падёт на поле боя, станет пищей собак. После этого, когда Кришна приблизился к Каши, Паундрака бодро вывел всю свою армию на поле боя, а его друг Кашираджа с подкреплением последовал за ним. Подобно всепожирающему огню, уничтожающему вселенную, Шри Кришна начал уничтожать армии Паундраки и Кашираджи Своим оружием со всех сторон. Затем Кришна сказал, что теперь Паундрака должен принудить Его отказаться от присвоенного имени Васудевы, и если он заставит Господа отказаться от сражения, Он сдастся Паундраке. Сказав эти слова, Кришна уничтожил колесницу Паундраки Своими острыми стрелами и обезглавил его Своей Сударшана-чакрой. Затем он отделил голову Кашираджи от его тела, и забросив её в Каши, вернулся в Двараку. Поскольку Паудрака одевался как Шри Хари и всегда помнил о Кришне, то он получил освобождение.
Когда супруга, дети и родственники царя Кашираджи увидели его отрубленную голову, то разрыдались. После этого, желая отомстить убийце отца, Судакшина, сын Кашираджи, начал выполнять суровые аскезы, чтобы удовлетворить Махадеву. Когда Махадева был удовлетворён его аскезами и молитвами, он спросил Судакшину, какое тот хочет благословение. Судакшина попросил дать ему средство, которым он сможет уничтожить убийцу своего отца. Махадэва дал ему наставление, как поклоняться огню Дакшинагни, в соответствии с предписаниями к ритуалу абхичара. Когда жертвоприношение было завершено, из жертвенного огня появилась грозная огненная форма питы с огненным трезубцем в руке. Этот демон направился в Двараку, а перепуганные жители Двараки побежали к Кришне, который тем временем играл в шахматы. Шри Кришна всех успокоил и приказал Сударшана-чакре уничтожить демона, созданного при помощи Махадевы. Когда Сударшана-чакра усмирил огненного демона, появившегося в результате проведения ритуала абхичара, он отправился в Варанаси и сжёг дотла грешных брахманов и самого Судакшину. После этого покидая город, Сударшана-чакра предал Варанаси огню и вернулся к Кришне.',NULL),('cb.antya.2.320.ru','cb.antya.2.320','cb-ru','В результате соблюдения строгих аскез, перед ним появился Шива и сказал: "Проси о благословении". Царь попросил о следующем.',NULL),('cb.antya.2.321.ru','cb.antya.2.321','cb-ru','"О Господь, я желаю лишь одного твоего благословения. Я хочу разгромить в бою Кришну".',NULL),('cb.antya.2.322.ru','cb.antya.2.322','cb-ru','Непостижимы качества Бхоланатхи Шанкары. Кто может понять, какой формой милости он награждает и кому он дарует её?',NULL),('cb.antya.2.323.ru','cb.antya.2.323','cb-ru','Он сказал: "О царь, иди и сражайся. Я буду следовать за тобой со своей свитой".',NULL),('cb.antya.2.324.ru','cb.antya.2.324','cb-ru','"Кто сможет одолеть тебя, если с тобой я и моё оружие Пашупата?"',NULL),('cb.antya.2.325.ru','cb.antya.2.325','cb-ru','Воодушевлённый Шивой глупый царь, радостно отправился воевать с Кришной.',NULL),('cb.antya.2.326.ru','cb.antya.2.326','cb-ru','Шива со своим окружением последовал за ним, намереваясь его поддержать.',NULL),('cb.antya.2.327.ru','cb.antya.2.327','cb-ru','Сын Деваки, Сверхдуша всех живых существ, моментально оценил сложившуюся ситуацию.',NULL),('cb.antya.2.328.ru','cb.antya.2.328','cb-ru','Зная положение, Кришначандра использовал Свою Сударшана чакру, чтобы уничтожить их всех.',NULL),('cb.antya.2.329.ru','cb.antya.2.329','cb-ru','Никто не может спастись от гнева Сударшаны. Сначала он снёс голову Каширадже.
Стих 330-333
sese tara sambandhe sakala varanasi 	pasupata-astra ki kariba cakra-sthane podaiya sakala karila bhasma-rasi 	 cakra-teja dekhi'' palaila sei-ksane
varanasi daha dekhi'' kruddha mahesvara 	sese mahesvara-prati yayena dhaiya pasupata-astra edilena bhayankara 	cakra-bhaye sankara yayena palaiya
За нанесённое царём оскорбление, в конечном счёте Сударшана сжёг дотла весь город Варанаси. Когда Махешвара увидел Варанаси в огне, он так осерчал, что пустил в ход своё грозное оружие Пашупата. Но что могло сделать оружие Пашупата Сударшане? Увидев доблестного Сударшану, Пашупата обратился в бегство. Затем Сударшана стал преследовать Махешвару, в ужасе убегающего от чакры.
В Шримад-Бхагаватам (10.66.42) говорится:
"После полного сожжения Варанаси, Сударшана-чакра Господа Вишну вернулся к Шри Кришне, который не приложил для всего случившегося никаких усилий".',NULL),('cb.antya.2.334.ru','cb.antya.2.334','cb-ru','Могущество Сударшаны ощущалось во всей вселенной и трёхглазый Шива не знал, где искать безопасное место.',NULL),('cb.antya.2.335.ru','cb.antya.2.335','cb-ru','Таким образом, Шива оказался в очень затруднительном положении. Так когда-то от доблести Сударшаны пострадал Дурваса.
Описания этого события можно найти в Шримад Бхагаватам (9.4).',NULL),('cb.antya.2.336.ru','cb.antya.2.336','cb-ru','В конце концов, Шива понял, "Никто кроме Кришны не сможет защитить меня от гнева Сударшаны".',NULL),('cb.antya.2.337.ru','cb.antya.2.337','cb-ru','Рассудив таким образом, перепуганный трёхглазый возвышенный вайшнав отправился за защитой к Говинде.',NULL),('cb.antya.2.338.ru','cb.antya.2.338','cb-ru','"Слава Верховному Господу, Деваки-нандане! Слава, слава всепроникающему Господу, прибежищу всех живых существ!"',NULL),('cb.antya.2.339.ru','cb.antya.2.339','cb-ru','"Слава, слава Тебе, наделяющему благостным и осквернённым разумом! Слава, слава тому кто создаёт, поддерживает и разрушает всё!"',NULL),('cb.antya.2.340.ru','cb.antya.2.340','cb-ru','"Слава Тебе, океан милости, который не ищет недостатков в других! Слава, слава единственному другу всех страдающих душ!"',NULL),('cb.antya.2.341.ru','cb.antya.2.341','cb-ru','"Слава, слава Тебе, кто избавляет от последствий проступков и даёт приют! Пожалуйста, прости мне моё оскорбление. Я предаюсь Тебе".',NULL),('cb.antya.2.342.ru','cb.antya.2.342','cb-ru','Услышав молитвы Шанкары, Господь всех живых существ отозвал Сударшану и предстал перед Шивой.',NULL),('cb.antya.2.343.ru','cb.antya.2.343','cb-ru','В окружении пастушков и девушек, Господь с еле заметной улыбкой, гневно заговорил.',NULL),('cb.antya.2.344.ru','cb.antya.2.344','cb-ru','"О Шива, ведь ты прекрасно знаешь Мою доблесть. Как же ты мог додуматься до такого?"',NULL),('cb.antya.2.345.ru','cb.antya.2.345','cb-ru','"Кто этот ничтожный, падший царь Кашираджа? Ради него ты сражался со Мной?"',NULL),('cb.antya.2.346.ru','cb.antya.2.346','cb-ru','"Ты видел Мою Сударшана-чакру, доблести которой не можешь противостоять даже ты".
Стих 347-348
"Могучее, несоурушимое оружие, как брахмастра и пашупатастра бессильны перед Сударшаной. Когда такое оружие терпит поражение, оно оборачивается против его обладателя".',NULL),('cb.antya.2.349.ru','cb.antya.2.349','cb-ru','"Похоже, что в мире не сыскать другого, кто не уважал бы Меня так, как ты".',NULL),('cb.antya.2.350.ru','cb.antya.2.350','cb-ru','Выслушав гневные слова Господа, Шанкара задрожал от страха.',NULL),('cb.antya.2.351.ru','cb.antya.2.351','cb-ru','Тогда Шива ухватился за лотосные стопы Господа, и со всей преданностью заговорил.
Стих 352-353
"О Господь, Ты управляешь всем миром. Кто может действовать независимо? Все люди мира подчинены тебе, как сухая трава покоряется ветру".
В Шримад Бхагаватам (10.63.44) сказано:
"Так давайте же поклоняться Верховному Господу, чтобы избавиться от материального существования. О Господь, Ты хранитель вселенной, а также причина её сотворения и разрушения. Одинаково расположенный ко всем и всегда умиротворённый, Ты настоящий друг, наша Душа и почитаемое Божество. Ты один, и другого такого нет. Ты прибежище всех миров и всех душ".
Следует также обратиься к Санти-парве, главе 43, стиху 16
и Анушасана-парве, главам 147-148, Махабхараты.
В Катха-упанишад (2.2.8
и 2.3.1) говорится: тасмин локах шритах сарве тад у натиети кашчана – "В Нём находятся все миры и Он непревзойдён".',NULL),('cb.antya.2.354.ru','cb.antya.2.354','cb-ru','"О Господь, живое существо действует следуя путём, которым Ты ведёшь его. Кто
обладает могуществом, чтобы преодолеть Твою иллюзорную энергию?"',NULL),('cb.antya.2.355.ru','cb.antya.2.355','cb-ru','"О Господь, так или иначе, Ты наделил меня ложным эго, и в результате, я посчитал себя непревзойдённым".
Ложное эго появляется под воздействием гуны невежества. По воле Верховного Господа, гуна-аватара Махадева наделён силой разрушения. Поэтому ложная философия, выдвинутая имперсоналистом Кашираджей, комментатором Шрикантхи, который был последователем философии шайва-вишиштадвайта и других имперсоналистов, как Апьяйа Дикшита, были полностью разоблачены в Шрута-пракашике, комментарии на шри-бхашью Шри Сударшаначарьи, слуги Шри Рамануджи. Тем не менее, когда философия шайва-вишиштадвайта подняла голову, она была разбита вдребезги оружием Сударшаны, принявшем форму философии шуддха-вишиштадвайта.
"В век Кали я принимаю форму брахмана и объясняю Веды посредством ложных писаний атеистического склада, подобным философии буддистов". Деятельность, о которой идёт речь в этом стихе, описывает миссию божества, формирующего ложное эго. Но Шри Вишнусвами, который был поглощён преданным служением Верховному Господу, принял прибежище у лотосных стоп Шри Рудры, своего духовного учителя, и так восстановил духовное эго в местах поклонения всем формам материального, ложного эго.',NULL),('cb.antya.2.356.ru','cb.antya.2.356','cb-ru','"Твоя иллюзорная энергия завела меня в тупик. О Господь, что же мне делать? Ведь я лишён независимости".
Как говорится: ‘майадхиша’ ‘майа-ваша’ ишваре-дживе бхеда, что означает "Господь – властелин энергий, а живое существо – их слуга. Вот в чём разница между Господом и живым существом". Поэтому, хотя Господа Шиву и называют Бхагаваном, он является подчинённым преданным вечного Господа Вишну.',NULL),('cb.antya.2.357.ru','cb.antya.2.357','cb-ru','"Только Твои лотосные стопы – вот мои жизнь и душа. Я отправлюсь жить в лес и там буду всегда помнить о Твоих лотосных стопах".',NULL),('cb.antya.2.358.ru','cb.antya.2.358','cb-ru','"Тем не менее, Ты наделил меня ложным эго. Что я могу поделать, О Господь, на это Твоя воля".
В Шримад Бхагаватам (2.10.12) сказано:
"Необходимо твёрдо знать, что материальные компоненты творения, деятельность, время, гуны, а также живые существа, созданные чтобы наслаждаться всем этим, существуют только по милости Господа, и как только Он перестаёт заботиться о них, все это уходит в небытие". И в Шримад Бхагаватам (10.88.3) сказано:
"Господь Шива неразлучен со своей энергией, материальной природой. Отвечая на молитвы трёх гун природы, он проявляет себя как материальное ложное эго трёх видов — в благости, в страсти и в невежестве".',NULL),('cb.antya.2.359.ru','cb.antya.2.359','cb-ru','"Тем не менее, О Господь, я совершил преступление. Пожалуйста, прости меня и одари Свою милостью".',NULL),('cb.antya.2.360.ru','cb.antya.2.360','cb-ru','"Господи, пожалуйста, благослови меня, чтобы никогда впредь такие мысли не одолевали меня".',NULL),('cb.antya.2.361.ru','cb.antya.2.361','cb-ru','"За преступление совершённое под влиянием ложного эго, я понёс справедливое наказание".',NULL),('cb.antya.2.362.ru','cb.antya.2.362','cb-ru','"О Господь, пожалуйста, дай мне Свои наставления. Где мне следует жить? Кого же мне спрашивать, как не Тебя?"',NULL),('cb.antya.2.363.ru','cb.antya.2.363','cb-ru','Услышав слова Шанкары, Господь улыбнулся и сочувственно произнёс.',NULL),('cb.antya.2.364.ru','cb.antya.2.364','cb-ru','"Послушай, Шива, я даю тебе божественное место. Ступай и живи там вместе со своим окружением".',NULL),('cb.antya.2.365.ru','cb.antya.2.365','cb-ru','"Название этого очаровательного места – Экамрака-вана. Ты будешь пребывать там в форме Коти-лингешвары".',NULL),('cb.antya.2.366.ru','cb.antya.2.366','cb-ru','"Это место так же приятно, как Варанаси. Я тоже проживаю там в самых скрытых местах".',NULL),('cb.antya.2.367.ru','cb.antya.2.367','cb-ru','"О Шива, сегодня я раскрыл тебе славу этого места. Никто кроме тебя не знает эту тайну".',NULL),('cb.antya.2.368.ru','cb.antya.2.368','cb-ru','"На берегу океана, под сенью древнего баньяна, есть просто чудесное место с названием Нилачала, которое ещё известно как Шри Пурушоттама-кшетра".
Слава Шри Пурушоттама-кшетры (Джаганнатха Пури) описана в одиннадцатой главе Крийя-йога-сары Падма пураны, так:
"На берегу соленого океана есть сакральный город, названный Пурушоттама. О лучший из брахманов, добраться до него труднее, чем достичь небес".
"Эксперты и знатоки имён называют этот город Пурушоттама, по причине того, что Верховная Личность Бога непосредственно пребывает там".
"О брахман, эта трудно достижимое священное место измеряется десятью йоджанами во всех направлениях. Воплощённые живые существа, проживающие там, имеют четырёхрукие формы полубогов".
"Каждый входящий в эту священную местность, принимает форму, подобную Господу Вишну. Тех, кто привержен двойственности, эта истина не касается".
"Даже если чандала прикоснётся к пище в этом месте, его следует считать возвышенной личностью. По причине того, что Сам Господь Вишну пребывает в этой пище, даже такого чандалу следует считать одним из лучших среди дваждырождённых".
"Повар, который готовит там пищу, это Лакшми, а наслаждается этой едой Сам Господь Джанардана. Поэтому, о мудрец среди брахманов, даже полубоги испытывают трудности в получении этих остатков".
"Эта еда – остатки трапезы Господа Хари, очищает и дарует редко достижимое в этом мире освобождение. Смертные, употребляющие прасад в пищу, освобождаются очень легко".
"Получить этот прасад не так просто даже полубогам, возглавляемым Брахмой.
Всякий раз, когда удаётся получить прасад, они принимают его с огромным почтением. Что говорить о простых смертных?"
"По мнению всех возвышенных мудрецов, тот чьё сердце не радуется этому редкому дару еды, тот противник Господа Вишну".
"Как воды Ганги очищают всю землю, о брахман, так щепотка этой еды очищает все места и уничтожает грехи".
"О лучший из брахманов, хотя эта божественная еда очень нежна на вкус, она действует словно молния, сокрушая гору грехов вкушающего".
"Совершивший преступления в предыдущих жизнях, вырывает с корнем их последствия, и благодаря этой еде, развивает преданность Богу".
"И те, чьи благочестивые плоды, полученные в течение многих жизней истощились, тоже обретают преданность, благодаря этому прасаду, о лучший из брахманов".',NULL),('cb.antya.2.369.ru','cb.antya.2.369','cb-ru','"Во время уничтожения бесчисленных вселенных, это место остаётся неизменным".',NULL),('cb.antya.2.370.ru','cb.antya.2.370','cb-ru','"Я вечно пребываю в этом месте, и каждый день принимаю там пищу".
Стих 371-372
"Под влиянием этого места, все живые существа, даже животные, насекомые и черви – все кто живут в радиусе десяти йоджан от этого места, выглядят как полубоги, имеющие четыре руки. Это место считается самым благоприятным местом в мире".',NULL),('cb.antya.2.373.ru','cb.antya.2.373','cb-ru','"Веды провозглашают, что просто сон в этом месте дарит плоды самадхи, а полежав там, можно обрести плоды предложения почтения Божеству".',NULL),('cb.antya.2.374.ru','cb.antya.2.374','cb-ru','"Путешествуя по этим местам, человек обретает благо, будто обходит вокруг Божества. Каждое слово сказанное в этом месте, становится предложенной Мне молитвой".',NULL),('cb.antya.2.375.ru','cb.antya.2.375','cb-ru','"Сила этого священного места такова, что даже человек употребляющий в пищу рыбу, достигает результата, обретаемого употреблением в пищу риса хавишья".
[В Ману-самхите] сказано: матсьядах сарва-мамсадас-тасман матсьйан виварджайет – "Тот, кто ест рыбу, считается пожирающим все виды плоти. Поэтому следует отказаться от рыбы". В соответствии с этим утверждением священного писания, тот кто ест рыбу, берёт на Себя грех поедания мяса всех видов живых существ. Поэтому грех от употребление в пищу рыбы является самым омерзительным, и есть её не следует.
Рис хавишья, или варёный рис и топлёное масло, является самой чистой едой. Он никогда не может быть нечистым. Для пребывающих в Шри-кшетре, благо от созерцания Мукунды всегда остаётся в силе, и даже если человек употреблял в пищу осквернённые продукты, как рыба, то такое греховное желание исчезает, когда он отведает прасад Господа Вишну, который становится для него более освящённым, чем рис хавишья. Заблудшие жители обители Господа, в десять йоджан, которые не понимают смысл пуран, открыто ввели в практику питание такими продуктами, как сушёная рыба. Если они откажутся от поедания этих отвратительных продуктов, то смогут повторять имя Хари. Хотя рис хавишья относится к пище в гуне благости, его нельзя приравнивать к трансцендентному маха-прасаду. Почитая трансцендентный маха-прасад, человек достигает чистого преданного служения Кришне.',NULL),('cb.antya.2.376.ru','cb.antya.2.376','cb-ru','"Это обитель, которая носит Моё имя, очень дорога Мне. Все, кто проживают там – подобны Мне".',NULL),('cb.antya.2.377.ru','cb.antya.2.377','cb-ru','"Ямараджа лишён права наказывать кого-то из проживающих в этом месте. Здесь Я Сам решаю вопросы награды праведников и наказания грешников".',NULL),('cb.antya.2.378.ru','cb.antya.2.378','cb-ru','"Для проживания Я выделяю тебе место к северу от этой Моей обители".
Местность к северу от Нилачалы с площадью около десяти квадратных йоджан, это Бхуванешвара.',NULL),('cb.antya.2.379.ru','cb.antya.2.379','cb-ru','"Это очаровательное место дарит материальное наслаждение и освобождение. Тебя там будут называть Шри Бхуванешварой".
Фраза бхукти-мукти-прада означает следующее: насладившись материальными удовольствиями или освободившись от них, люди обретают способность поклоняться Верховному Господу. Другое прочтение для бхукти-мукти-прада, это бхакти-муктипрада, или "дающий освобождение в форме преданного служения". В этом случае, преданное служение рассматривается как дополнение к служению фактически освобождённого живого существа.',NULL),('cb.antya.2.380.ru','cb.antya.2.380','cb-ru','После того, как Шанкара услышал об удивительной славе Джаганнатха Пури, он снова обхватил лотосные стопы Господа и произнёс.',NULL),('cb.antya.2.381.ru','cb.antya.2.381','cb-ru','"О Господь моей жизни, у меня есть одна просьба. Гордость всегда владеет мной".',NULL),('cb.antya.2.382.ru','cb.antya.2.382','cb-ru','"Поэтому проживание без общения с Тобой, не сулит мне ничего хорошего".',NULL),('cb.antya.2.383.ru','cb.antya.2.383','cb-ru','"Я бы хотел жить рядом с Тобой, поскольку в дурном окружении нет ничего хорошего".',NULL),('cb.antya.2.384.ru','cb.antya.2.384','cb-ru','"Поэтому, если Ты считаешь меня Своим слугой, пожалуйста, дай мне место гденибудь в Твоей обители".',NULL),('cb.antya.2.385.ru','cb.antya.2.385','cb-ru','"Услышав из Твоих лотосных уст о славе Твоей обители, я воспылал сильным желанием поселиться там".',NULL),('cb.antya.2.386.ru','cb.antya.2.386','cb-ru','"Я буду подобострастно служить Тебе, как прислуга. О Господь, пожалуйста, дай мне самый малый кусочек земли".',NULL);